// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Check field カテゴリー -  default value ', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Check field カテゴリー -  default value ', async function() {
    await driver.get("http://localhost:4200/admin-user/list-department");
    await driver.manage().window().setRect({ width: 1936, height: 1056 });
    await driver.findElement(By.css(".ant-typography")).click();
    await driver.findElement(By.css("#create_template_form_catergory > .ant-radio-wrapper-checked .ant-radio-input")).click();
    assert(await driver.findElement(By.css("#create_template_form_catergory > .ant-radio-wrapper-checked .ant-radio-input")).isSelected());
    assert(!await driver.findElement(By.css("#create_template_form_catergory > .ant-radio-wrapper:nth-child(2) .ant-radio-input")).isSelected());
    assert(!await driver.findElement(By.css("#create_template_form_catergory > .ant-radio-wrapper:nth-child(3) .ant-radio-input")).isSelected());
  });
});
